<?php include 'db.php';$order_by=isset($_GET['order_by'])?$_GET['order_by']:'pub_date';$search_query=isset($_GET['search'])?'%' . $_GET['search'] . '%':'%';$sql="SELECT * FROM news WHERE title LIKE ? ORDER BY $order_by DESC";$stmt=$conn->prepare($sql);$stmt->bind_param("s",$search_query);$stmt->execute();$result=$stmt->get_result();?><!doctype html><html lang="es"><head><meta charset="UTF-8"><meta content="width=device-width,initial-scale=1" name="viewport"><title>Lector RSS</title><link href="css/style.css" rel="stylesheet"><link href="https://fonts.googleapis.com/css2?family=Roboto:wght@400;700&display=swap" rel="stylesheet"></head><body><h1><img alt="Logo RSS" src="imagenes/logo.png" style="height:50px;vertical-align:middle;margin-right:10px"> Lector de Feeds RSS</h1><form method="GET"><input name="search" placeholder="Buscar noticias..." value="<?=htmlspecialchars($_GET['search']??'')?>"><button type="submit">Buscar</button></form><table border="1"><thead><tr><th><a href="?order_by=pub_date">Fecha</a></th><th><a href="?order_by=title">Título</a></th><th><a href="?order_by=category">Categoría</a></th><th>Descripción</th><th>Enlace</th></tr></thead><tbody><?php while($row=$result->fetch_assoc()): ?><tr><td><?=$row['pub_date']?></td><td><?=$row['title']?></td><td><?=$row['category']?></td><td><?=substr($row['description'],0,100)?>...</td><td><a href="<?=$row['link']?>" target="_blank">Leer más</a></td></tr><?php endwhile; ?></tbody></table><footer><a href="add_feed.php">Agregar Feed</a> | <a href="update_feeds.php">Actualizar Noticias</a> | <a href="index.php">Volver</a></footer><script src="js/script.js"></script></body></html>
